sql:
SELECT boundary_name
FROM boundaries
WHERE boundary_type = 'ward';

SELECT COUNT(representative_id) AS democrat_count
FROM representatives
WHERE party = 'Democrat';

SELECT num_seats
FROM chambers
ORDER BY num_seats DESC;

SELECT num_seats
FROM chambers
WHERE chamber_id = 1;

external_knowledge:
- Large populations refer to areas with more than 10,000 residents; 
- Chambers with many seats have more than one seat allocated;
- Higher-than-average voter participation refers to an average metric value greater than 0.5, which indicates a voter turnout rate above the average.

sql:
SELECT chamber_id, COUNT(representative_id) AS num_representatives
FROM representatives
GROUP BY chamber_id;

SELECT boundary_name, population
FROM boundaries
WHERE boundary_id = '1';

SELECT boundary_name, AVG(population) AS avg_population
FROM boundaries
GROUP BY boundary_name;

SELECT boundary_name, population
FROM boundaries
WHERE population = (SELECT MAX(population) FROM boundaries);
